/**
 * ApiKeyScopeService
 *
 * Validates whether an API key has the required scope.
 *
 * Scope System:
 * - 'read:activities' → Can GET activity data
 * - 'write:activities' → Can POST/PUT/PATCH activities
 * - 'read:fleet' → Can GET fleet data
 * - 'read:profile' → Can GET profile endpoints
 * - '*' → Wildcard, grants all scopes
 *
 * Amendment 2: Designed for future prefix matching support.
 * Current implementation uses exact match + wildcard.
 * Future: Can enable prefix matching (e.g., 'write:*') without logic rewrite.
 */

export class ApiKeyScopeService {
  /**
   * Check if an API key has a required scope.
   *
   * Supports:
   * - Exact match: scopes=['read:activities'], required='read:activities' → true
   * - Wildcard: scopes=['*'], required='anything' → true
   * - Future prefix: scopes=['read:*'], required='read:activities' → true (if enabled)
   *
   * @param scopes - Array of scopes granted to the API key (from UserApiKey.scopes)
   * @param required - The scope required for the endpoint (e.g., 'write:activities')
   * @returns true if the API key has the required scope, false otherwise
   */
  hasScope(scopes: string[] | undefined, required: string): boolean {
    if (!scopes?.length) {
      return false;
    }

    // Wildcard grants all
    if (scopes.includes('*')) {
      return true;
    }

    // Exact match
    if (scopes.includes(required)) {
      return true;
    }

    // Future: Prefix matching (disabled for MVP)
    // Uncomment and update VALID_SCOPES when expanding to 'write:*', 'read:*'
    //
    // Example:
    // const [requiredAction, requiredResource] = required.split(':');
    // if (scopes.some(s => s === `${requiredAction}:*`)) return true;
    //
    // This would allow:
    // - scopes=['write:*'] to match required='write:activities'
    // - scopes=['read:*'] to match required='read:fleet'

    return false;
  }
}
